(gen_random_uuid(), (SELECT id FROM products WHERE name ILIKE '%Benediktiner Weissbier%' LIMIT 1), 'Những dòng cá Koi lai tạo tiền tỉ tung tăng đảo lượn qua vầng đá rêu xanh tĩnh lặng. Thú vui tao nhã ngàn đô này tìm bến đỗ trong giọt lúa mì Benediktiner Weissbier êm thấm thấu lòng người.', 'Facebook', 'draft', '['/images/products/premium_ugc/weissbier_exact_koipond_1775178713095.png']'::jsonb, 'demo-tenant'),
(gen_random_uuid(), (SELECT id FROM products WHERE name ILIKE '%Bitburger%' LIMIT 1), 'Lắp ráp mô tuýp linh kiện đồ hoạ dải Neon màu siêu tốc độ mang lại trải nghiệm màn hình căng đét. Bitburger Pils sát cánh làm nguội lạnh cơn rát bão táp trên dàn máy không biên giới tựa IT thượng cấp.', 'Facebook', 'draft', '['/images/products/premium_ugc/bitburger_exact_pcbuild_1775178754628.png']'::jsonb, 'demo-tenant'),
(gen_random_uuid(), (SELECT id FROM products WHERE name ILIKE '%Benediktiner Dunkel%' LIMIT 1), 'Dòng thơ gai góc chạm nổi cộp cộp từ chiếc đánh chữ kim loại xước mẻ qua hằng thập kỷ. Sự bền bỉ dấn thân về con chữ không bao giờ tróc vảy khi thưởng cùng hương gỗ sồi từ Benediktiner Dunkel.', 'Facebook', 'draft', '['/images/products/premium_ugc/dunkel_exact_typewriter_1775178774531.png']'::jsonb, 'demo-tenant'),
(gen_random_uuid(), (SELECT id FROM products WHERE name ILIKE '%Benediktiner Weissbier%' LIMIT 1), 'Gió luồng vi vu qua cửa kính chiếc xe siêu sang Maybach chạy băng xuyên nẻo thành thị màu xám vệt sáng chói chang. Ghế da trắng mịn ngóng về chân lý cùng dư âm Benediktiner Weissbier nồng đậm.', 'Facebook', 'draft', '['/images/products/premium_ugc/benediktiner_exact_maybach_1775178801110.png']'::jsonb, 'demo-tenant'),
(gen_random_uuid(), (SELECT id FROM products WHERE name ILIKE '%Bitburger%' LIMIT 1), 'Tủ trưng bày hộp Acrylic trong suốt soi rọi hào quang của nhãn hiệu giày quý hiếm. Bản hoà ca thời trang giới trẻ không lùi bước được thắp lên ngọn sóng chát chua nhẹ mà mê đắm của Bitburger Pils vô đối.', 'Facebook', 'draft', '['/images/products/premium_ugc/bitburger_exact_sneakers_1775178823294.png']'::jsonb, 'demo-tenant'),
(gen_random_uuid(), (SELECT id FROM products WHERE name ILIKE '%Benediktiner Weissbier%' LIMIT 1), 'Chiêm nghiệm nét phác cọ phóng khoáng khó giải nghĩa bên trong khối sảnh sáng trưng nghệ thuật trừu tượng. Đọng lại một cõi an nhiên rũ bỏ bụi bặm, cầm chắc Benediktiner Weissbier êm trôi ngọc ngà.', 'Facebook', 'draft', '['/images/products/premium_ugc/weissbier_exact_artgallery_1775178843655.png']'::jsonb, 'demo-tenant'),
(gen_random_uuid(), (SELECT id FROM products WHERE name ILIKE '%Benediktiner Dunkel%' LIMIT 1), 'Phố buôn Tokyo ngập nước ướt loá đèn biển Neon ám thị tương lai đổ khuôn Blade Runner. Hóng bát Ramen tươm hơi và nâng niêng đậm đặc Benediktiner Dunkel mạch nha cháy bùi bùi trứ danh xua tan tẻ nhạt đêm thâu.', 'Facebook', 'draft', '['/images/products/premium_ugc/dunkel_exact_noodleshop_1775178869555.png']'::jsonb, 'demo-tenant'),
(gen_random_uuid(), (SELECT id FROM products WHERE name ILIKE '%Bitburger%' LIMIT 1), 'Vệt bùn khô dính bánh gài tời đất trên mẫu xe địa hình gai góc xuyên thủng đồi dốc thông rì rào. Cuộc thử thách gan lỳ chưa từng thoái lui để đổi lấy phút nhấp Bitburger Pils mát nghẹn họng cực sảng khoái vỡ tơi.', 'Facebook', 'draft', '['/images/products/premium_ugc/bitburger_exact_mtbike_1775178891904.png']'::jsonb, 'demo-tenant'),
(gen_random_uuid(), (SELECT id FROM products WHERE name ILIKE '%Bitburger%' LIMIT 1), 'Chiếc thùng giữ lạnh Yeti thép quân sự uy nghi toạ lạc bãi dã chiến nhí nhố ánh mặt trời tản ngã. Tống một cụm Bitburger Pils sắc lẻm thâu tóm nhịp đập sinh khí để xạc lại năng lượng phiêu lưu hoang dã bứt phá.', 'Facebook', 'draft', '['/images/products/premium_ugc/bitburger_exact_yeti_1775178932655.png']'::jsonb, 'demo-tenant'),
(gen_random_uuid(), (SELECT id FROM products WHERE name ILIKE '%Benediktiner Weissbier%' LIMIT 1), 'Nhìn ra sân Golf chải rạp góc nhìn đồi dốc trải dài khuất bóng chân trời đổ nắng nheo mắt thèm thuồng. Chiến thắng ngoạn mục cuối ngày khép lại bến đậu yên cả cùng ánh vàng lúa non của Benediktiner Weissbier hảo hạng đê mê.', 'Facebook', 'draft', '['/images/products/premium_ugc/weissbier_exact_golfclubhouse_1775178957218.png']'::jsonb, 'demo-tenant'),
(gen_random_uuid(), (SELECT id FROM products WHERE name ILIKE '%Benediktiner Dunkel%' LIMIT 1), 'Tiếng vang phím nốt đàn dương cầm lạch cạch đan chéo vạch âm nhạc thính phòng u sầu trang trọng tột bậc rọi sáng một góc đèn. Nỗi cô đơn quyền thế nhâm nhi vị đắng gắt caramel từ Benediktiner Dunkel như giải phẫu linh hồn.', 'Facebook', 'draft', '['/images/products/premium_ugc/dunkel_exact_piano_1775178976240.png']'::jsonb, 'demo-tenant'),
(gen_random_uuid(), (SELECT id FROM products WHERE name ILIKE '%Benediktiner Weissbier%' LIMIT 1), 'Ngồi co ro lọt giữa cáp treo lướt dốc tuyết Alps chẻ toạc đám mây mù quấn theo gió réo. Thu gọn đỉnh nóc thế giới qua lớp kính và đút túi một vị trái phả thoang thoảng dịu êm của Benediktiner Weissbier thanh mát vô cùng tột đỉnh.', 'Facebook', 'draft', '['/images/products/premium_ugc/benediktiner_exact_gondola_1775178997496.png']'::jsonb, 'demo-tenant');
